### Option 2: HTML/JavaScript (using Three.js)
If you want to see a rendered 3D model in your web browser immediately, you can copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any browser.

**Instructions:**
1. Copy the code below.
2. Save it as `house.html`.
3. Open the file in Chrome, Firefox, or Edge.

```html
<!DOCTYPE html>
<html>
<head>
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; }
        canvas { display: block; }
    </style>
</head>
<body>
    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue

        const camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(10, 10, 10);
        camera.lookAt(0, 0, 0);

        const renderer = new THREE.WebGLRenderer();
        renderer.setSize(window.innerWidth, window.innerHeight);
        document.body.appendChild(renderer.domElement);

        // 2. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 0.8);
        dirLight.position.set(10, 20, 10);
        scene.add(dirLight);

        // 3. Create the House
        const houseGroup = new THREE.Group();

        // Materials
        const wallMaterial = new THREE.MeshLambertMaterial({ color: 0x8B4513 }); // Brown
        const roofMaterial = new THREE.MeshLambertMaterial({ color: 0x800080 }); // Purple
        const glassMaterial = new THREE.MeshLambertMaterial({ color: 0xADD8E6, transparent: true, opacity: 0.6 });

        // Walls (BoxGeometry)
        const wallGeo = new THREE.BoxGeometry(6, 4, 6);
        const walls = new THREE.Mesh(wallGeo, wallMaterial);
        houseGroup.add(walls);

        // Roof (ConeGeometry)
        const roofGeo = new THREE.ConeGeometry(5, 3, 4); // 4 segments for pyramid look
        roofGeo.rotateX(Math.PI / 2); // Rotate to point up
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 5.5; // Lift it above the wall
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(1.5, 3, 0.2);
        const doorMat = new THREE.MeshLambertMaterial({ color: 0x333333 });
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 1.5, 3.1); // Front center
        houseGroup.add(door);

        // Windows
        const winGeo = new THREE.BoxGeometry(1.5, 1.5, 0.1);
        const win1 = new THREE.Mesh(winGeo, glassMaterial);
        win1.position.set(-1.5, 2.5, 3.05);
        const win2 = new THREE.Mesh(winGeo, glassMaterial);
        win2.position.set(1.5, 2.5, 3.05);
        houseGroup.add(win1);
        houseGroup.add(win2);

        // Ground
        const groundGeo = new THREE.PlaneGeometry(50, 50);
        const groundMat = new THREE.MeshLambertMaterial({ color: 0x228B22 });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        scene.add(ground);

        scene.add(houseGroup);

        // 4. Animation Loop
        function animate() {
            requestAnimationFrame(animate);

            // Simple rotation for effect
            houseGroup.rotation.y += 0.005;

            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```
